#pragma once

#include "../core/DCBlocker.h"
#include "../core/Oversampler.h"
#include "../core/SanityCheck.h"
#include <algorithm>
#include <cmath>

namespace dnb::dsp::dist {

// Soft/Hard clipping stage with internal OS and DC Blocking for asymmetrical
// distortion. Used for Character tone shaping.
class Saturator {
public:
  enum class Type { SoftClip, HardClip, Foldback };

  Saturator() = default;

  void prepare(double newSampleRate, size_t maxBlockSize) {
    sampleRate = newSampleRate;
    // Require 4x oversampling for standard nonlinear operations
    // per ADR-002 TechStack guidelines.
    os.prepare(sampleRate, core::Oversampler::Factor::x4, maxBlockSize);
    dcBlocker.reset();
    dcBlocker.setCoefficient(0.995f);
  }

  void setParameters(Type newType, float newDriveLinear) {
    type = newType;
    drive = newDriveLinear;
  }

  // Process a block
  void processBlock(float *buffer, size_t numSamples) {
    // 1. Up-sample
    float *oversampled = os.processUp(buffer, numSamples);
    size_t osSamples = numSamples * 4;

    // 2. Process non-linear
    for (size_t i = 0; i < osSamples; ++i) {
      float s = oversampled[i] * drive;

      switch (type) {
      case Type::SoftClip:
        // Fast approx tanh
        s = s / (1.0f + std::abs(s));
        break;
      case Type::HardClip:
        s = std::clamp(s, -1.0f, 1.0f);
        break;
      case Type::Foldback:
        s = std::sin(s);
        break;
      }

      oversampled[i] = s;
    }

    // 3. Down-sample back into buffer
    os.processDown(buffer, numSamples);

    // 4. Cleanup DC generated by potential asymmetry and enforce sanity
    for (size_t i = 0; i < numSamples; ++i) {
      buffer[i] = dcBlocker.process(buffer[i]);
      core::SanityCheck::ensureSafe(buffer[i]);
    }
  }

private:
  double sampleRate = 44100.0;
  Type type = Type::SoftClip;
  float drive = 1.0f;

  core::Oversampler os;
  core::DCBlocker dcBlocker;
};

} // namespace dnb::dsp::dist
